public int countCode(String str) {
    int count = 0;
    for(int i = 0; i <= str.length() - 4; i++) {
        String sub = str.substring(i, i + 4);
        if(sub.startsWith("co") && sub.charAt(3) == 'e') {
            count++;
        }
    }
    return count;
}

