public String alarmClock(int day, boolean vacation) {
    String alarmTime = "";

    // Check if it's a weekday or weekend
    if (day >= 1 && day <= 5) {
        // If it's a weekday, check if we're on vacation
        if (vacation) {
            alarmTime = "10:00";
        } else {
            alarmTime = "7:00";
        }
    } else {
        // If it's a weekend, check if we're on vacation
        if (vacation) {
            alarmTime = "off";
        } else {
            alarmTime = "10:00";
        }
    }

    return alarmTime;
}

public String atFirst(String str) {
    if (str.isEmpty()) { 
        return "@@"; 
    } else if (str.length() == 1) { 
        return str + "@"; 
    } else if (str.length() > 1) { 
        return str.substring(0, 2); 
    } else { 
        return ""; 
    }
}

public int loneSum(int a, int b, int c) {
    int sum = 0;
    Set<Integer> uniqueNumbers = new HashSet<>();

    if (!uniqueNumbers.contains(a)) {
        uniqueNumbers.add(a);
        sum += a;
    }

    if (!uniqueNumbers.contains(b)) {
        uniqueNumbers.add(b);
        sum += b;
    }

    if (!uniqueNumbers.contains(c)) {
        uniqueNumbers.add(c);
        sum += c;
    }

    return sum;
}

